  const afterSources = body.slice(idx);
  const firstNewline = afterSources.indexOf("\n");
  if (firstNewline === -1) return false;
  const sectionBody = afterSources.slice(firstNewline + 1);
  const nextHeadingOffset = sectionBody.search(/^##/m);
