async function startCuriosityScanner() {
  if (scannerStarted) {
    console.log("[Curiosity] Scanner already started \u2014 ignoring duplicate call");
    return;
  }
  scannerStarted = true;
  console.log("[Curiosity] Scanner started \u2014 runs every 30 minutes");
  setInterval(
    async () => {
      console.log("[Curiosity] Running scan...");
      await runCuriosityScan();
    },
    30 * 60 * 1e3
  );
  setInterval(
    async () => {
      console.log("[Curiosity] Running daily history cleanup...");
      await cleanupOldCuriosityHistory();
    },
    24 * 60 * 60 * 1e3
  );
  setTimeout(() => runCuriosityScan(), 60 * 1e3);
  setTimeout(() => cleanupOldCuriosityHistory(), 5 * 60 * 1e3);
}

